-static void print_args_to_stderr(const char **args) {
-    for (const char **argp = args; *argp != NULL; ++argp) {
-        const char *s = *argp;
-        if (argp != args) {
-            fputc(' ', stderr);
-        }
-        // https://unix.stackexchange.com/a/357932/296319
-        if (!strpbrk(s, " \t\n!\"#$&'()*,;<=>?[\\]^`{|}~")) {
-            fputs(s, stderr);
-            continue;
-        }
-        fputc('\'', stderr);
-        for (; *s; ++s) {
-            if (*s != '\'') {
-                fputc(*s, stderr);
-            } else {
-                fputs("'\\''", stderr);
-            }
-        }
-        fputc('\'', stderr);
-    }
-}
