-        *arg++ = log_file;
-    }
-
-    const char* tail[] = {
-        "--exec-cmd", "--", self, "restorewait",
-        NULL
-    };
-    char *criuopts = getenv("CRAC_CRIU_OPTS");
-    if (criuopts) {
-        char* criuopt = strtok(criuopts, " ");
-        while (criuopt && ARRAY_SIZE(args) >= (size_t)(arg - args + ARRAY_SIZE(tail))) {
