-static int post_resume(void) {
-    char *pidstr = getenv("CRTOOLS_INIT_PID");
-    if (!pidstr) {
-        fprintf(stderr, MSGPREFIX "cannot find CRTOOLS_INIT_PID env\n");
-        return 1;
-    }
