+static const char *path_abs(const char *rel) {
+    if (rel[0] == '/') {
+        return rel;
+    }
+    char *cwd = get_current_dir_name();
+    if (!cwd) {
+        perror("get_current_dir_name");
+        exit(1);
+    }
+    return join_path(cwd, rel);
+}
